## Section1(not reported)
## Problem1(1.2.9.9)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "contextForm.pl",
  "contextInequalitySetBuilder.pl",
  "parserGraphTool.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
$var = list_random('a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
Context()->variables->are($var => 'Real');
$c = list_random(4,6,8,10,12);
$a = ($c == 4) ? list_random(2,4) :
     ($c == 6) ? list_random(2,3,6) :
     ($c == 8) ? list_random(2,4,8) :
     ($c == 10) ? list_random(2,5,10) :
     list_random(2,3,4,6,12);
$c = list_random(-$c, $c);
$b = -$c/$a;
$left = Formula("-$var/$a")->reduce;
$right = Formula("$b")->reduce;
$sign = list_random('\lt', '\gt', '\leq', '\geq');
%interval = (
  '\lt'  => "($c, inf)",
  '\gt'  => "(-inf, $c)",
  '\leq' => "[$c, inf)",
  '\geq' => "(-inf, $c]"
);
Context("Interval");
$interval = Interval($interval{$sign});
InequalitySetBuilder::UseVerticalSuchThat();
Context("InequalitySetBuilder-Only");
Context()->variables->are($var => 'Real');
%perlsign = (
  '\lt'  => ">",
  '\gt'  => "<",
  '\leq' => ">=",
  '\geq' => "<="
);
$perlsign = $perlsign{$sign};
$setbuilder = Compute("{ $var | $var $perlsign $c}");
$gt = GraphTool("{interval, $interval}")->with(
  availableTools => ['IntervalTool', 'IncludeExcludePointTool'],
  numberLine => 1,
  xAxisLabel => "$var",
  bBox => [ -16, 16 ],
  ticksDistanceX => 4,
  minorTicksX => 3,
  useBracketEnds => 1,
  showInStatic => 0,
  showCoordinateHints => 0,
);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the inequality.

[`[$left][$sign][$right]`]

[_]{$gt}{1}

[@KeyboardInstructions('In interval notation.')@]**

[_]{$interval}{12}

[@KeyboardInstructions('In set-builder notation. (If needed, type [|inf|]* or [|infinity|]* for [`\infty\text{,}`] [|>=|]* for [`\geq\text{,}`] and [|<=|]* for [`\leq\text{.}`])')@]**

[_]{$setbuilder}{12}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
